#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        int count = 0;
        for (int i = 0; i < n - 1; i++) {
            if (s[i] == '<' && s[i + 1] == '>') {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

