code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = s.length();
            int count = 0;
            for (int i = 0; i < n - 1; i++) {
                if (s.charAt(i) == '<' && s.charAt(i + 1) == '>') {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

